var body = $input.first().json.body || $input.first().json;
var tenantId = String(body.tenantId || '');
var documentType = body.documentType ? String(body.documentType) : null;
var documentId = body.documentId ? String(body.documentId) : null;
var page = body.page ? parseInt(body.page) : 1;
var limit = body.limit ? parseInt(body.limit) : 50;
var offset = (page - 1) * limit;

var UUID_RE = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;

if (!tenantId || !UUID_RE.test(tenantId)) {
  throw new Error('Tenant ID requis et doit être un UUID valide');
}

if (documentId && !UUID_RE.test(documentId)) {
  throw new Error('Document ID doit être un UUID valide');
}

return [{
  json: {
    tenantId: tenantId,
    documentType: documentType,
    documentId: documentId,
    page: page,
    limit: limit,
    offset: offset
  }
}];

var countResult = $('05. Count').first().json;
var listItems = $('06. List').all();
var parser = $('02. Parser').first().json;
var total = parseInt(countResult.total) || 0;
var totalPages = Math.ceil(total / parser.limit) || 1;

var entries = listItems.map(function(item) {
  var json = item.json;
  return {
    id: json.id,
    documentType: json.document_type,
    documentId: json.document_id,
    etape: json.etape,
    etapePrecedente: json.etape_precedente,
    etapeSuivante: json.etape_suivante,
    dateEtape: json.date_etape,
    utilisateur: json.utilisateur,
    commentaire: json.commentaire,
    hashVerification: json.hash_verification,
    metadata: json.metadata,
    createdAt: json.created_at
  };
});

return [{json: {
  success: true,
  entries: entries,
  pagination: {
    total: total,
    page: parser.page,
    limit: parser.limit,
    totalPages: totalPages
  }
}}];
